mapper.delete:
UPDATE esg.tb_equipment_info
SET
    use_yn = 'N',
    updated_at = now(),
    updated_by = #{updatedBy}
WHERE equipment_id = #{equipmentId}

mapper.update:
UPDATE esg.tb_dataset_typeofequipment
SET
    use_yn = 'N',
    updated_at = now(),
    updated_by = #{updatedBy}
WHERE comp_id = #{compId}
    AND std_eq_id = #{stdEqId}

mapper.select:
        SELECT tei.*,
               tdt.std_eq_nm
        FROM esg.tb_equipment_info tei
	    LEFT JOIN esg.tb_dataset_typeofequipment tdt ON tdt.std_eq_id = tei.std_eq_id AND tdt.comp_id = tei.comp_id
        where tei.comp_id = #{compId}
			and tei.std_eq_id = #{searchText}
